#
# Structure for table "cs_attendance_rule"
#

DROP TABLE IF EXISTS `cs_attendance_rule`;
CREATE TABLE `cs_attendance_rule` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `rule_name` varchar(100) NOT NULL COMMENT '规则名称',
  `rule_details` varchar(100) NOT NULL DEFAULT '' COMMENT '规则详情',
  `applicable_dept` varchar(100) DEFAULT NULL COMMENT '适用部门',
  `effective_date` date DEFAULT NULL COMMENT '生效日期',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=6 DEFAULT CHARSET=utf8 COMMENT='考勤规则配置';

