#
# Structure for table "cs_dept_training_jlrequest"
#

DROP TABLE IF EXISTS `cs_dept_training_jlrequest`;
CREATE TABLE `cs_dept_training_jlrequest` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title_id` varchar(255) DEFAULT NULL COMMENT '培训编号',
  `dept_name` varchar(100) NOT NULL COMMENT '申请部门',
  `request_by` varchar(50) NOT NULL COMMENT '申请人',
  `training_topic` varchar(100) NOT NULL COMMENT '培训主题',
  `reason` text COMMENT '申请理由',
  `expected_time` varchar(50) DEFAULT NULL COMMENT '期望培训时长',
  `request_status` varchar(50) DEFAULT NULL COMMENT '处理状态',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='培训需求';

#
# Data for table "cs_dept_training_jlrequest"
#

/*!40000 ALTER TABLE `cs_dept_training_jlrequest` DISABLE KEYS */;
/*!40000 ALTER TABLE `cs_dept_training_jlrequest` ENABLE KEYS */;

#
# Structure for table "cs_employee_lifecycle"
#

DROP TABLE IF EXISTS `cs_employee_lifecycle`;
CREATE TABLE `cs_employee_lifecycle` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `lifecycle_name` varchar(50) NOT NULL COMMENT '姓名',
  `id_card` varchar(18) DEFAULT NULL COMMENT '身份证号',
  `hire_date` date DEFAULT NULL COMMENT '入职日期',
  `leave_date` date DEFAULT NULL COMMENT '离职日期',
  `lifecycle_status` varchar(50) DEFAULT NULL COMMENT '当前状态',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='员工全生命周期';

#
# Data for table "cs_employee_lifecycle"
#

/*!40000 ALTER TABLE `cs_employee_lifecycle` DISABLE KEYS */;
