#
# Structure for table "cs_evaluation_result"
#

DROP TABLE IF EXISTS `cs_evaluation_result`;
CREATE TABLE `cs_evaluation_result` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `employee` varchar(32) NOT NULL COMMENT '员工',
  `title_id` varchar(100) NOT NULL COMMENT '培训编号',
  `eval_period` varchar(20) NOT NULL COMMENT '考核周期（如2026Q1）',
  `score` decimal(5,2) NOT NULL COMMENT '考核得分',
  `comment` text COMMENT '评语',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='培训考核结果';

#
# Data for table "cs_evaluation_result"
#

