#
# Structure for table "cs_evaluation_scheme"
#

DROP TABLE IF EXISTS `cs_evaluation_scheme`;
CREATE TABLE `cs_evaluation_scheme` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title_id` varchar(100) NOT NULL COMMENT '培训编号',
  `scheme_name` varchar(100) NOT NULL COMMENT '考核名称',
  `eval_period` varchar(20) NOT NULL COMMENT '适用考核周期',
  `criteria` varchar(20) DEFAULT NULL COMMENT '考核内容',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='考核方案';

