#
# Structure for table "cs_leave_ygapplication"
#

DROP TABLE IF EXISTS `cs_leave_ygapplication`;
CREATE TABLE `cs_leave_ygapplication` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `employee` varchar(32) NOT NULL COMMENT '员工',
  `dept` varchar(32) NOT NULL COMMENT '部门',
  `leave_type` varchar(32) NOT NULL COMMENT '请假类型',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `reason` text COMMENT '请假原因',
  `application_status` varchar(32) DEFAULT NULL COMMENT '审批状态',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='假期申请';

#
# Data for table "cs_leave_ygapplication"
#

/*!40000 ALTER TABLE `cs_leave_ygapplication` DISABLE KEYS */;
/*!40000 ALTER TABLE `cs_leave_ygapplication` ENABLE KEYS */;

#
# Structure for table "cs_recruitment_post"
#

DROP TABLE IF EXISTS `cs_recruitment_post`;
CREATE TABLE `cs_recruitment_post` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `position_name` varchar(100) NOT NULL COMMENT '岗位名称',
  `department` varchar(100) NOT NULL COMMENT '部门',
  `work_location` varchar(100) DEFAULT NULL COMMENT '工作地点',
  `job_description` text COMMENT '岗位描述',
  `requirements` text COMMENT '任职要求',
  `post_status` varchar(100) DEFAULT NULL COMMENT '招聘状态',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='招聘岗位发布表';

#
# Data for table "cs_recruitment_post"
