#
# Structure for table "cs_resume_screening"
#

DROP TABLE IF EXISTS `cs_resume_screening`;
CREATE TABLE `cs_resume_screening` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `candidate_name` varchar(50) NOT NULL COMMENT '候选人姓名',
  `apply_position` varchar(100) NOT NULL COMMENT '应聘岗位',
  `phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `email` varchar(100) DEFAULT NULL COMMENT '邮箱',
  `resume_file_path` varchar(255) DEFAULT NULL COMMENT '简历文件路径',
  `screening_status` varchar(255) DEFAULT NULL COMMENT '筛选状态',
  `screening_note` text COMMENT '筛选备注',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='简历筛选表';

#
