/*!40000 ALTER TABLE `cs_resume_screening` ENABLE KEYS */;

#
# Structure for table "cs_resume_yhscreening"
#

DROP TABLE IF EXISTS `cs_resume_yhscreening`;
CREATE TABLE `cs_resume_yhscreening` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `candidate_name` varchar(50) NOT NULL COMMENT '候选人姓名',
  `apply_position` varchar(100) NOT NULL COMMENT '应聘岗位',
  `phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `email` varchar(100) DEFAULT NULL COMMENT '邮箱',
  `resume_file_path` varchar(255) DEFAULT NULL COMMENT '简历文件路径',
  `screening_status` varchar(255) DEFAULT NULL COMMENT '筛选状态',
  `screening_note` text COMMENT '筛选备注',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='简历筛选表';

#
# Data for table "cs_resume_yhscreening"
#

/*!40000 ALTER TABLE `cs_resume_yhscreening` DISABLE KEYS */;
/*!40000 ALTER TABLE `cs_resume_yhscreening` ENABLE KEYS */;

#
# Structure for table "cs_salary_detail"
#

DROP TABLE IF EXISTS `cs_salary_detail`;
CREATE TABLE `cs_salary_detail` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `employee` varchar(32) NOT NULL COMMENT '员工',
  `dept` varchar(32) NOT NULL COMMENT '部门',
  `salary_month` varchar(32) NOT NULL COMMENT '薪资月份',
  `base_salary` decimal(10,2) NOT NULL COMMENT '基本工资',
  `performance_bonus` decimal(10,2) DEFAULT '0.00' COMMENT '绩效奖金',
  `overtime_pay` decimal(10,2) DEFAULT '0.00' COMMENT '加班费',
  `deduction` decimal(10,2) DEFAULT '0.00' COMMENT '扣款',
  `net_salary` decimal(10,2) NOT NULL COMMENT '实发工资',
  `detail_info` text COMMENT '详情',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='薪资明细表';

#
# Data for table "cs_salary_detail"
#

