#
# Structure for table "cs_salary_item_config"
#

DROP TABLE IF EXISTS `cs_salary_item_config`;
CREATE TABLE `cs_salary_item_config` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `item_name` varchar(50) NOT NULL COMMENT '薪资项目名称',
  `applicable_dept` varchar(100) DEFAULT NULL COMMENT '适用部门',
  `post` varchar(100) DEFAULT NULL COMMENT '适用范围',
  `salay_details` varchar(100) NOT NULL DEFAULT '' COMMENT '薪资详情',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='薪资项目配置';

#
# Data for table "cs_salary_item_config"
#

/*!40000 ALTER TABLE `cs_salary_item_config` DISABLE KEYS */;
