#
# Structure for table "cs_training_notice"
#

DROP TABLE IF EXISTS `cs_training_notice`;
CREATE TABLE `cs_training_notice` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title_id` varchar(100) NOT NULL COMMENT '培训编号',
  `title` varchar(100) NOT NULL COMMENT '通知标题',
  `content` text NOT NULL COMMENT '通知内容',
  `publish_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '发布时间',
  `training_time` datetime DEFAULT NULL COMMENT '培训时间',
  `location` varchar(100) DEFAULT NULL COMMENT '培训地点',
  `target_dept` varchar(100) DEFAULT NULL COMMENT '部门',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=207 DEFAULT CHARSET=utf8 COMMENT='培训通知';

#
# Data for table "cs_training_notice"
#

