/*!40000 ALTER TABLE `cs_training_notice` ENABLE KEYS */;

#
# Structure for table "cs_training_plan"
#

DROP TABLE IF EXISTS `cs_training_plan`;
CREATE TABLE `cs_training_plan` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title_id` varchar(100) NOT NULL COMMENT '培训编号',
  `plan_name` varchar(100) NOT NULL COMMENT '计划名称',
  `dept_target` varchar(100) DEFAULT NULL COMMENT '目标部门',
  `training_content` text NOT NULL COMMENT '培训内容',
  `start_date` date NOT NULL COMMENT '开始日期',
  `end_date` date NOT NULL COMMENT '结束日期',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='培训计划';

#
# Data for table "cs_training_plan"
