#
# Structure for table "cs_welfare_info"
#

DROP TABLE IF EXISTS `cs_welfare_info`;
CREATE TABLE `cs_welfare_info` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `employee` varchar(32) NOT NULL COMMENT '员工',
  `welfare_type` varchar(50) NOT NULL COMMENT '福利类型',
  `money` int(11) NOT NULL COMMENT '福利金额',
  `description` text COMMENT '福利详情',
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=206 DEFAULT CHARSET=utf8 COMMENT='福利信息';

